import {{ Injectable }} from '@nestjs/common';
import {{ SyncService }} from './models/sync.model';
import {{ SyncServiceRepository }} from './repositories/sync.repository';

@Injectable()
export class SyncServiceService {{
  constructor(
    private readonly repository: SyncServiceRepository,
  ) {{}}

  async findAll(): Promise<SyncService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<SyncService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<SyncService>): Promise<SyncService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<SyncService>): Promise<SyncService> {{
    return this.repository.update(id, data);
  }}
}}
